import React, { useEffect, useState } from "react";

function App() {
  const [incidents, setIncidents] = useState([]);
  const [component, setComponent] = useState("");
  const [message, setMessage] = useState("");
  const [loading, setLoading] = useState(false);

  const fetchIncidents = async () => {
  const res = await fetch("http://127.0.0.1:8000/incidents");
  const data = await res.json();
  setIncidents(data);
};

  useEffect(() => {
    fetchIncidents();

    const interval = setInterval(() => {
      fetchIncidents();
    }, 2000);

    return () => clearInterval(interval);
  }, []);

  const sendSignal = async () => {
    if (!component || !message) {
      alert("⚠️ Please enter Component ID and Message");
      return;
    }

    const res = await fetch(
      `http://127.0.0.1:8000/ingest?component_id=${component}&message=${message}`,
      { method: "POST" }
    );

    const data = await res.json();

    if (!res.ok) {
      alert("❌ " + data.detail);
    } else {
      alert("✅ Incident Created Successfully");
      setComponent("");
      setMessage("");
      fetchIncidents();
    }
  };

  const addRCA = async (id) => {
    const root = prompt("Root Cause:");
    const fix = prompt("Fix:");

    const res = await fetch(
      `http://127.0.0.1:8000/incident/${id}/rca?root_cause=${root}&fix=${fix}`,
      { method: "POST" }
    );

    const data = await res.json();

    if (!res.ok) {
      alert("❌ " + data.detail);
    } else {
      alert("✅ RCA Added Successfully");
    }

    fetchIncidents();
  };

  const closeIncident = async (id) => {
    const res = await fetch(
      `http://127.0.0.1:8000/incident/${id}/status?status=CLOSED`,
      { method: "PUT" }
    );

    const data = await res.json();

    if (!res.ok) {
      let message = data.detail;

      if (message.includes("Invalid transition")) {
        message = "⚠️ Please move incident to RESOLVED before closing";
      }

      if (message.includes("RCA required")) {
        message = "⚠️ Please add RCA before closing the incident";
      }

      alert(message);
    } else {
      alert("✅ Incident Closed Successfully");
    }

    fetchIncidents();
  };

  const updateStatus = async (id, status) => {
    const res = await fetch(
      `http://127.0.0.1:8000/incident/${id}/status?status=${status}`,
      { method: "PUT" }
    );

    const data = await res.json();

    if (!res.ok) {
      alert("❌ " + data.detail);
    } else {
      alert(`✅ Moved to ${status}`);
    }

    fetchIncidents();
  };
return (
  <div style={{ padding: "20px" }}>
    <h1>🚨 Incident Dashboard</h1>

    {/* Input Section */}
    <div style={{ marginBottom: "15px" }}>
      <input
        placeholder="Component ID"
        value={component}
        onChange={(e) => setComponent(e.target.value)}
      />
      <input
        placeholder="Message"
        value={message}
        onChange={(e) => setMessage(e.target.value)}
      />
      <button onClick={sendSignal}>Send Signal</button>
    </div>

    <hr />

    <h2>Incidents</h2>

    {/* Incident List */}
    {incidents.map((inc) => (
      <div
        key={inc.id}
        style={{
          border: "1px solid #ccc",
          borderRadius: "8px",
          margin: "10px",
          padding: "15px",
          boxShadow: "0 2px 5px rgba(0,0,0,0.1)",
          backgroundColor:
            inc.severity === "P0"
              ? "#ffe5e5"
              : inc.severity === "P1"
              ? "#fff8e1"
              : "#f4f4f4"
        }}
      >
        <h3>Incident #{inc.id}</h3>

        <p><b>Component:</b> {inc.component_id}</p>
        <p><b>Severity:</b> {inc.severity}</p>

        <p>
          <b>Status:</b>{" "}
          <span style={{ color: "blue" }}>{inc.status}</span>
        </p>

        <p><b>Signals:</b> {inc.signals.length}</p>

        {inc.rca && (
          <>
            <p><b>Root Cause:</b> {inc.rca.root_cause}</p>
            <p><b>Fix:</b> {inc.rca.fix}</p>
            <p><b>MTTR:</b> {Math.round(inc.rca.mttr_seconds)} sec</p>
          </>
        )}

        <div style={{ marginTop: "10px" }}>
          <button
            onClick={() => updateStatus(inc.id, "INVESTIGATING")}
            disabled={inc.status !== "OPEN"}
          >
            Investigate
          </button>

          <button
            onClick={() => updateStatus(inc.id, "RESOLVED")}
            disabled={inc.status !== "INVESTIGATING"}
          >
            Resolve
          </button>

          <button
            onClick={() => addRCA(inc.id)}
            disabled={inc.status !== "RESOLVED" || inc.rca}
          >
            Add RCA
          </button>

          <button
            onClick={() => closeIncident(inc.id)}
            disabled={inc.status !== "RESOLVED" || !inc.rca}
          >
            Close
          </button>
        </div>
      </div>
    ))}
  </div>
);
}

export default App;
